replace_generated<-"--replace-generated-output"%in%commandArgs(trailingOnly=TRUE);out<-file.path(v5,"FINAL_EXTERNAL_SCRNA_VALIDATION_REPORT_V2.md");if(file.exists(out)&&!replace_generated)stop("Output exists: ",out)
e<-fread(file.path(v5,"external_scrna_evidence_matrix_v2.csv"));sp<-fread(file.path(v5,"macrophage_spp1_presence_by_sample.csv"));rep<-fread(file.path(v5,"macrophage_spp1_reproducibility_by_dataset.csv"));enr<-fread(file.path(v5,"macrophage_spp1_relative_enrichment.csv"));state<-fread(file.path(v5,"macrophage_state_reproducibility_calibrated.csv"));c6<-fread(file.path(v5,"GSE147082_cluster6_subcluster_annotation.csv"));cnv<-fread(file.path(v5,"GSE147082_PT2834_target_cluster_cnv_sensitivity.csv"));recv<-fread(file.path(v5,"epithelial_receiver_context_by_sample.csv"));author<-fread(file.path(v5,"author_subtype_program_distribution.csv"))
line_spp1<-function(ds){z<-rep[dataset_id==ds];ez<-enr[dataset_id==ds&evaluable==TRUE&SPP1_relative_enrichment=="RELATIVELY_ENRICHED"];paste0(z$n_present_patients,"/",z$n_evaluable_patients," evaluable patients PRESENT; reproducibility=",z$SPP1_reproducibility_status,"; relatively enriched samples=",if(nrow(ez))paste(paste(ez$patient_id,ez$sample_id,sep="/"),collapse="; ")else"none at percentile >=0.60")}
state_line<-function(ds,st){z<-state[dataset_id==ds&state==st];paste0(st," ",z$reproducibility_status," (",z$n_present_patients,"/",z$n_evaluable_patients,")")}
ctx_line<-function(ds){z<-e[dataset_id==ds];paste0("CD44=",z$CD44_receiver_status,", ITGB1=",z$ITGB1_receiver_status,", dual-positive=",z$dual_positive_receiver_status,", context=",z$sender_receiver_context_status)}
msp<-author[grepl("Macro_SPP1",cell_type_original)];mcq<-author[grepl("Macro_C1QC",cell_type_original)]
lines<-c("# Final external scRNA validation report v2","","## Statistical definitions","","SPP1/state presence, cross-patient reproducibility and relative enrichment are distinct outputs. Presence uses evaluable samples and high-state fractions; reproducibility counts patients with at least one evaluable PRESENT sample; within-dataset median percentile >=0.60 is used only for relative enrichment. Cells are never treated as independent statistical replicates.","","## 1. SPP1 presence, reproducibility and relative enrichment","",paste0("- GSE154600: ",line_spp1("GSE154600"),". This dataset supports cross-patient SPP1 macrophage presence even though no patient median exceeds the relative-enrichment percentile threshold."),paste0("- GSE147082: ",line_spp1("GSE147082"),"."),paste0("- GSE158722: ",line_spp1("GSE158722"),". P07_Time1 is evaluable and PRESENT; P04_Time3 is evaluable but ABSENT_OR_LOW under the joint positive/high-fraction rule. All other small timepoints remain descriptive and are NOT_EVALUABLE_FOR_REPLICATION, not negative."),paste0("- GSE151214: ",line_spp1("GSE151214"),"; normal-reference evidence only."),paste0("- GSE154763: ",line_spp1("GSE154763"),"; author-annotated myeloid-reference evidence only."),"","## 2. C1QC and FOLR2 calibration","",paste0("- GSE154600: ",state_line("GSE154600","C1QC"),"; ",state_line("GSE154600","FOLR2"),"."),paste0("- GSE147082: ",state_line("GSE147082","C1QC"),"; ",state_line("GSE147082","FOLR2"),"."),paste0("- GSE158722: ",state_line("GSE158722","C1QC"),"; ",state_line("GSE158722","FOLR2"),"; small-sample support only."),"SPP1, C1QC and FOLR2 can coexist at the presence level. Relative enrichment identifies which patient/sample is shifted within its own dataset and must not be used to negate presence.","","## 3. Why GSE154600 is not SPP1-negative","",paste0("All five evaluable patients are PRESENT: ",paste(sp[dataset_id=="GSE154600",paste0(patient_id," positive=",sprintf("%.3f",SPP1_positive_fraction),", high=",sprintf("%.3f",SPP1_high_macrophage_fraction))],collapse="; "),". Therefore SPP1 cross-patient presence is REPLICATED. The absence of a sample median percentile >=0.60 only means no patient is relatively enriched by that separate criterion."),"","## 4. GSE147082 cluster 6","",paste0("True FindAllMarkers results support: ",paste(c6[,paste0("subcluster ",subcluster," ",final_annotation," n=",n_cells," markers=",top20_real_differential_markers)],collapse="; "),". The former two identically named Cytotoxic_T groups are now CD8_effector_T and Cycling_CD8_effector_T; cycling is interpreted as a state. Gamma_delta_T remains distinct."),"","## 5. PT-2834 patient-internal CNV-like sensitivity","",paste0("Cluster 4: ",cnv[group=="cluster_4",interpretation],"; epithelial-profile correlation=",sprintf("%.3f",cnv[group=="cluster_4",correlation_to_broad_epithelial]),". Cluster 7: ",cnv[group=="cluster_7",interpretation],". Method=exploratory_patient_internal_cnv_like. Only 15 broad-lineage epithelial reference cells were available, so this is a candidate-level sensitivity result, not definitive malignant-cell classification."),"","## 6. Epithelial CD44/ITGB1 receiver context","",paste0("- GSE154600: ",ctx_line("GSE154600"),"."),paste0("- GSE147082: ",ctx_line("GSE147082"),"."),paste0("- GSE158722: ",ctx_line("GSE158722"),"."),"ITGB1 receiver support is stronger than CD44 in the evaluable tumor datasets; dual-positive fractions are detected at low levels. Receivers are broad-lineage Epithelial and are not described as uniformly confirmed malignant cells. The result is an SPP1-associated epithelial CD44/ITGB1 context, not a proven direct ligand-receptor interaction.","","## 7. GSE154763 author-subtype validation","",paste0("Macro_SPP1: SPP1 program median=",sprintf("%.3f",msp$SPP1_program_median),". Macro_C1QC: SPP1=",sprintf("%.3f",mcq$SPP1_program_median),", C1QC=",sprintf("%.3f",mcq$C1QC_program_median),", FOLR2=",sprintf("%.3f",mcq$FOLR2_program_median),". Primary validation is based on whole author-subtype distributions; single-cell module_state remains sensitivity analysis only."),"","## 8. Evidence freeze and limitations","","The v2 matrix removes eligible_for_primary_conclusion and instead records tumor-context eligibility and explicit support flags. Dataset roles remain fixed. GSE158722 is INCONCLUSIVE rather than negative. No result proves direct binding, causal regulation or directionality; PT-2834 CNV-like classification and all sender/receiver results remain descriptive and require orthogonal or experimental validation.")
